/* eslint-disable */
// Section 3 — Financial Modeling
// P1 Smart Invoice: faithful viewer of the canonical Excel workbook
// (models/Mal_P1_SmartInvoice.xlsx · 18 sheets). Reads window.MAL_P1_DATA
// (auto-generated by models/sync_p1_to_jsx.py — never edit by hand).
// P2/P3/P4: locked "in progress" cards.
//
// Excel is the single source of truth. JSX never recomputes the model.

const { useState: fS, useMemo: fM, useCallback: fCB } = React;

// ============================================================
// Formatting helpers
// ============================================================
const aedM = (n, dp = 1) => 'AED ' + (Number.isFinite(n) ? n.toFixed(dp) : '0') + 'M';
const aedB = (n, dp = 2) => 'AED ' + (Number.isFinite(n) ? (n / 1000).toFixed(dp) : '0') + 'B';
const pct  = (n, dp = 1) => (Number.isFinite(n) ? n.toFixed(dp) : '0') + '%';
const ratio = (n, dp = 2) => (Number.isFinite(n) ? n.toFixed(dp) : '0') + 'x';

function aedSmart(n) {
  if (!Number.isFinite(n)) return 'AED 0';
  if (Math.abs(n) >= 1000) return aedB(n, 2);
  return aedM(n, 1);
}

