// ============================================================
// Section root
// ============================================================
function SectionFinancial({ lang, isMobile }) {
  const flagshipId = 'p1-smart-invoice';
  const [activeProductId, setActiveProductId] = fS(flagshipId);
  const [tourOpen, setTourOpen] = fS(false);
  const isAr = lang === 'ar';
  const data = window.MAL_P1_DATA;
  const catalogue = window.MAL_PRODUCT_CATALOGUE || [];
  const product = window.MAL_PRODUCT_BY_ID?.[activeProductId];

  if (!data) {
    return (
      <div className="mal-section-page" style={{ padding: 60, textAlign: 'center' }}>
        <h1 style={{ fontFamily: 'var(--mal-font-display)', fontStyle: 'italic' }}>Economics</h1>
        <p style={{ color: 'var(--mal-mid)' }}>
          Model data not loaded. Run <code>.venv-models/bin/python models/sync_p1_to_jsx.py</code> to regenerate.
        </p>
      </div>
    );
  }

  const isLive = product?.status === 'live';
  const Tour = window.MalTour;
  const TourBtn = window.MalTourButton;
  const tourSteps = isLive ? buildEconomicsTourSteps(data, isAr) : [];

  return (
    <div className="mal-section-page" dir={isAr ? 'rtl' : 'ltr'}>
      {/* Top row: dropdown + Excel download (left) · tour button (right) */}
      <div style={{
        display: 'flex', justifyContent: 'space-between',
        alignItems: 'center', gap: 16, flexWrap: 'wrap',
        marginBottom: 22,
      }}>
        <div data-tour-id="econ-selector" style={{ display: 'flex', alignItems: 'center', gap: 10, flexWrap: 'wrap' }}>
          <FinGroupedProductSelector
            catalogue={catalogue}
            productId={activeProductId}
            onPickProduct={setActiveProductId}
            isAr={isAr} isMobile={isMobile}/>
          {isLive && (
            <a href={`models/${data.meta.workbook}`} download={data.meta.workbook}
               title={`${data.meta.workbook} · ${data.meta.sheets} sheets · synced ${data.meta.lastUpdated}`}
               className="mal-excel-cta"
               style={{
                 display: 'inline-flex', alignItems: 'center', gap: 8,
                 padding: '9px 16px', borderRadius: 999,
                 background: '#107C41',
                 border: '1px solid #0E6939',
                 color: '#FFFFFF',
                 fontSize: 12.5, fontWeight: 600, letterSpacing: '0.01em',
                 textDecoration: 'none',
                 transition: 'background .15s, transform .15s',
               }}
               onMouseEnter={(e) => {
                 e.currentTarget.style.background = '#0E6939';
                 e.currentTarget.style.transform = 'translateY(-1px)';
               }}
               onMouseLeave={(e) => {
                 e.currentTarget.style.background = '#107C41';
                 e.currentTarget.style.transform = 'translateY(0)';
               }}>
              <DownloadArrowIcon/>
              <ExcelIcon/>
              <span>{isAr ? 'تحميل إكسل' : 'Download Excel'}</span>
            </a>
          )}
        </div>
        {TourBtn && isLive && (
          <TourBtn lang={lang} onStart={() => setTourOpen(true)}/>
        )}
      </div>

      {isLive && <P1Workbench data={data} isMobile={isMobile} isAr={isAr}/>}
      {!isLive && product && <InProgressCard product={product} isAr={isAr}/>}

      {Tour && tourOpen && (
        <Tour steps={tourSteps} onClose={() => setTourOpen(false)} isOpen={tourOpen} lang={lang}/>
      )}
    </div>
  );
}

