// ============================================================
// P1 Workbench — scenario picker (interactive) + dashboard (read-only)
// ============================================================
function P1Workbench({ data, isMobile, isAr }) {
  const [scenario, setScenario] = fS('base');
  const scen = data.scenarios[scenario];

  const exportCsv = fCB(() => {
    const yrs = ['y1','y2','y3','y4','y5'];
    const cols = ['avgBook','grossInt','fundingCost','nim','lossProvision','ram','opex','netContrib','equity'];
    const head = ['Line', ...yrs.map((y) => y.toUpperCase())].join(',');
    const rows = cols.map((k) => [k, ...yrs.map((y) => data.pnl[y][k].toFixed(2))].join(','));
    const csv = [head, ...rows].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob); a.download = 'mal-p1-pnl-5yr.csv'; a.click();
  }, [data]);

  return (
    <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '320px 1fr', gap: 24, alignItems: 'start' }}>
      {/* ============= LEFT: sticky lever panel ============= */}
      <StickyLeverPanel data={data} isMobile={isMobile} isAr={isAr}/>

      {/* ============= RIGHT: dashboard ============= */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 22, minWidth: 0 }}>
        <HeroKpis data={data} isAr={isAr}/>
        <ScenarioPickerBar scenario={scenario} setScenario={setScenario} scen={scen}
                           data={data} isAr={isAr}/>
        <DisbursementSection data={data} isMobile={isMobile} isAr={isAr}/>
        <PLSection data={data} isMobile={isMobile} isAr={isAr}/>
        <RiskSection data={data} isMobile={isMobile} isAr={isAr}/>
        <CapitalFundingSection data={data} isMobile={isMobile} isAr={isAr}/>
        <UnitEconomicsSection data={data} isMobile={isMobile} isAr={isAr}/>
        <VintageCohortsSection data={data} isMobile={isMobile} isAr={isAr}/>
        <ScenarioCompareSection data={data} isAr={isAr}/>
        <BreakEvenSection data={data} isAr={isAr}/>
        <SensitivitySection data={data} isAr={isAr}/>
        <SyncFooter data={data} exportCsv={exportCsv} isAr={isAr}/>
      </div>
    </div>
  );
}

// ============================================================
// Hero KPIs (5-yr summary)
// ============================================================
function HeroKpis({ data, isAr }) {
  const fy = data.fiveYearSummary;
  const r3 = data.ratios.y3;
  return (
    <div data-tour-id="econ-hero" className="mal-fade-up" style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
      <MalKpi label={isAr ? 'الصرف ٥ سنوات (وجه)' : '5-yr disbursement (face)'}
              value={aedB(fy.face, 1)}
              sub={isAr ? '٢٥٠M → ١٣B' : 'Y1 250M → Y5 13B'}/>
      <MalKpi label={isAr ? 'مساهمة صافية تراكمية' : 'Cum. net contribution'}
              value={aedM(fy.cumNetContrib, 0)}
              sub={isAr ? '٥ سنوات' : 'Y1 → Y5'}/>
      <MalKpi label={isAr ? 'العائد على الأصول · Y3' : 'ROA · Y3'}
              value={pct(r3.roaPct, 2)}
              deltaTone={r3.roaPct >= 5 ? 'up' : 'down'}
              sub={isAr ? `Y5: ${pct(data.ratios.y5.roaPct, 2)}` : `Y5: ${pct(data.ratios.y5.roaPct, 2)}`}/>
      <MalKpi label={isAr ? 'العائد المعدل بالمخاطر · Y3' : 'RAROC · Y3'}
              value={pct(r3.rarocPct, 0)}
              deltaTone={r3.rarocPct >= 20 ? 'up' : 'down'}
              sub={isAr ? 'مقابل ٢٠٪ هدف' : 'vs 20% target'}/>
      <MalKpi label={isAr ? 'حقوق الملكية المرفوعة' : 'Equity raised (cum.)'}
              value={aedM(fy.totalEquityRaised, 0)}
              sub={isAr ? 'بذرة + سلسلة A/B/C' : 'Seed + A + B + C'}/>
      <MalKpi label={isAr ? 'الكتاب الذروة (Y5)' : 'Peak avg book (Y5)'}
              value={aedB(fy.avgBookPeak, 1)}
              sub={isAr ? 'متوسط' : 'avg'}/>
    </div>
  );
}

// ============================================================
// Scenario picker bar — pills + Y3 readout
// ============================================================
function ScenarioPickerBar({ scenario, setScenario, scen, data, isAr }) {
  const base = data.scenarios.base;
  const delta = (k) => scen[k] - base[k];
  const pctDelta = (k) => base[k] !== 0 ? ((scen[k] / base[k] - 1) * 100) : 0;
  return (
    <div data-tour-id="econ-scenarios" className="mal-fade-up" style={{
      background: 'var(--mal-paper)', border: '1px solid var(--mal-line)',
      borderRadius: 'var(--mal-r-lg)', padding: 18,
    }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 12, marginBottom: 14 }}>
        <div>
          <div style={{ fontSize: 13, fontWeight: 600 }}>
            {isAr ? 'لوحة السيناريوهات · Y3' : 'Scenario panel · Y3 readout'}
          </div>
          <div style={{ fontSize: 11, color: 'var(--mal-mid)', marginTop: 2 }}>
            {isAr ? 'انقر للتبديل · القيم محسوبة مسبقاً في إكسل' : 'Click to switch · values pre-computed in Excel (Scenarios tab)'}
          </div>
        </div>
        <div style={{ display: 'flex', gap: 6 }}>
          {SCENARIOS.map((s) => (
            <button key={s.key} onClick={() => setScenario(s.key)} style={{
              all: 'unset', cursor: 'pointer',
              padding: '8px 14px', borderRadius: 999,
              fontSize: 12, fontWeight: 600,
              background: scenario === s.key ? 'var(--mal-ink)' : 'var(--mal-surface-2)',
              color: scenario === s.key ? '#FAF7EE' : 'var(--mal-ink)',
              border: '1px solid var(--mal-line)',
              transition: 'all .15s',
            }}>{s.label}</button>
          ))}
        </div>
      </div>
      <div style={{ display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))',
                    gap: 10, marginTop: 6 }}>
        <ScenarioTile label={isAr ? 'كتاب Y3' : 'Y3 book'} v={aedM(scen.totalBook, 0)} d={pctDelta('totalBook')}/>
        <ScenarioTile label={isAr ? 'إيراد إجمالي' : 'Gross int.'} v={aedM(scen.grossInt, 1)} d={pctDelta('grossInt')}/>
        <ScenarioTile label="NIM" v={aedM(scen.nim, 1)} d={pctDelta('nim')}/>
        <ScenarioTile label={isAr ? 'الخسارة' : 'Loss'} v={aedM(scen.loss, 1)} d={pctDelta('loss')} invertedDelta/>
        <ScenarioTile label="OpEx" v={aedM(scen.opex, 1)} d={pctDelta('opex')} invertedDelta/>
        <ScenarioTile label={isAr ? 'مساهمة صافية' : 'Net contrib'} v={aedM(scen.netContrib, 1)} d={pctDelta('netContrib')}/>
        <ScenarioTile label="ROA" v={pct(scen.roaPct * 100, 2)} d={((scen.roaPct - base.roaPct) * 100).toFixed(2) + ' pts'} raw/>
        <ScenarioTile label="RAROC" v={pct(scen.rarocPct * 100, 1)} d={((scen.rarocPct - base.rarocPct) * 100).toFixed(1) + ' pts'} raw/>
      </div>
    </div>
  );
}

function ScenarioTile({ label, v, d, invertedDelta = false, raw = false }) {
  const positive = raw ? !d.startsWith('-') : (invertedDelta ? d <= 0 : d >= 0);
  const tone = positive ? 'var(--mal-success)' : 'var(--mal-danger)';
  return (
    <div style={{
      padding: '10px 12px', borderRadius: 12,
      background: 'var(--mal-surface-2)', border: '1px solid var(--mal-line-2)',
    }}>
      <div style={{ fontSize: 10, fontWeight: 600, color: 'var(--mal-mid-2)',
                    textTransform: 'uppercase', letterSpacing: '.06em' }}>{label}</div>
      <div style={{ fontFamily: 'var(--mal-font-display)', fontStyle: 'italic',
                    fontSize: 18, lineHeight: 1.1, marginTop: 4 }}>{v}</div>
      <div style={{ fontSize: 10.5, color: tone, marginTop: 2, fontWeight: 500 }}>
        {raw ? d : (typeof d === 'number' ? (d >= 0 ? '+' : '') + d.toFixed(1) + '%' : d)}
      </div>
    </div>
  );
}

// ============================================================
// Disbursement section — 5-yr stacked + composition
// ============================================================
function DisbursementSection({ data, isMobile, isAr }) {
  const yrs = ['y1','y2','y3','y4','y5'];
  const tracks = data.tracks;
  return (
    <div data-tour-id="econ-disb" style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '2fr 1fr', gap: 22 }}>
      <ChartCard title={isAr ? 'الصرف ٥ سنوات (AED M)' : 'Disbursement plan · Y1 → Y5 (AED M)'}
                 sub={isAr ? 'صرف وجه الفاتورة (face value)' : 'Face value of invoices funded'}>
        <MalBarChart
          height={220}
          data={yrs.map((y) => ({
            label: y.toUpperCase(),
            value: data.disbursement[y].face,
            tone: 'iri',
          }))}
          formatValue={(v) => v >= 1000 ? (v/1000).toFixed(1) + 'B' : v.toFixed(0) + 'M'}
        />
      </ChartCard>
      <ChartCard title={isAr ? 'تكوين الكتاب · Y3' : 'Book composition · Y3'}
                 sub={isAr ? 'مرجح بالخليط × المدة' : 'Weighted by mix × tenor'}>
        <MalStackedBar
          segments={[
            { label: 'Pay-30',    value: tracks.pay30.y3.avgBook, color: 'var(--mal-primary)' },
            { label: 'BNPL',      value: tracks.bnpl.y3.avgBook,  color: 'var(--mal-primary-3)' },
            { label: 'Extension', value: tracks.ext.y3.avgBook,   color: 'var(--mal-iri-2)' },
          ]}
          formatLabel={(v) => v.toFixed(0) + 'M'}
        />
        <div style={{ marginTop: 14, fontSize: 11.5, lineHeight: 1.6, color: 'var(--mal-mid)' }}>
          {isAr
            ? `BNPL تحمل ٦٤٪ من الكتاب · المدة ١٠٥ يوم`
            : `BNPL carries 64% of book · 105-day tenor`}
        </div>
      </ChartCard>
    </div>
  );
}

// ============================================================
// P&L section — margin walk + 5-yr table
// ============================================================
function PLSection({ data, isMobile, isAr }) {
  const r3 = data.ratios.y3;
  const yrs = ['y1','y2','y3','y4','y5'];
  return (
    <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr', gap: 22 }}>
      <div data-tour-id="econ-margin">
      <ChartCard title={isAr ? 'تدرج الهامش · Y3 (% الكتاب)' : 'Margin walk · Y3 (% of book)'}
                 sub={isAr ? 'إجمالي → بعد التكلفة → بعد الخسائر → الصافي' : 'Gross → −CoF → −Loss → −OpEx → Net'}>
        <MalBarChart
          height={240}
          data={[
            { label: 'Gross',  value: +(r3.nimPct + (r3.lossPct - r3.lossPct) + 6.5).toFixed(2), tone: 'iri' },
            { label: '− CoF',  value: +r3.nimPct.toFixed(2), tone: 'iri' },
            { label: '− Loss', value: +(r3.nimPct - r3.lossPct).toFixed(2), tone: 'iri' },
            { label: '− OpEx', value: +(r3.nimPct - r3.lossPct - r3.opexPct).toFixed(2), tone: 'success' },
          ]}
          formatValue={(v) => v.toFixed(1) + '%'}
        />
        <div style={{ marginTop: 12, fontSize: 11.5, color: 'var(--mal-mid)', lineHeight: 1.6 }}>
          ROA Y3: <strong>{pct(r3.roaPct, 2)}</strong> · RAROC: <strong>{pct(r3.rarocPct, 0)}</strong>
        </div>
      </ChartCard>
      </div>
      <ChartCard title={isAr ? 'المساهمة الصافية ٥ سنوات' : 'Net contribution · Y1 → Y5 (AED M)'}>
        <MalLineChart
          height={240}
          labels={yrs.map((y) => y.toUpperCase())}
          series={[{ name: 'NC', values: yrs.map((y) => data.pnl[y].netContrib),
                     color: 'var(--mal-primary)' }]}
          formatValue={(v) => v.toFixed(0) + 'M'}
        />
        <div style={{ marginTop: 12, fontSize: 11.5, color: 'var(--mal-mid)', lineHeight: 1.6 }}>
          {isAr ? 'تراكمي ٥ سنوات: ' : 'Cumulative Y1→Y5: '}
          <strong>{aedM(data.fiveYearSummary.cumNetContrib, 0)}</strong>
        </div>
      </ChartCard>
      <div data-tour-id="econ-pnl-table" style={{ gridColumn: isMobile ? 'auto' : '1 / -1' }}>
        <PnLTable data={data} isAr={isAr}/>
      </div>
    </div>
  );
}

function PnLTable({ data, isAr }) {
  const yrs = ['y1','y2','y3','y4','y5'];
  const rows = [
    [isAr ? 'متوسط الكتاب' : 'Avg book',                 'avgBook',       false],
    [isAr ? 'إيراد إجمالي' : 'Gross interest income',    'grossInt',      false],
    [isAr ? 'تكلفة التمويل' : '− Funding cost',          'fundingCost',   true],
    [isAr ? 'NIM' : 'NIM',                               'nim',           false, 'total'],
    [isAr ? 'مخصص الخسائر' : '− Loss provision',         'lossProvision', true],
    [isAr ? 'هامش معدل بالمخاطر' : 'Risk-adjusted margin','ram',          false, 'total'],
    [isAr ? 'مصاريف التشغيل' : '− OpEx',                'opex',           true],
    [isAr ? 'المساهمة الصافية' : 'Net contribution',     'netContrib',    false, 'total'],
    [isAr ? 'حقوق الملكية المخصصة' : 'Equity allocated', 'equity',        false, 'sub'],
  ];
  return (
    <ChartCard title={isAr ? 'الربح والخسارة ٥ سنوات (AED M)' : 'Pro-forma P&L · Y1 → Y5 (AED M)'}>
      <div style={{ overflowX: 'auto' }}>
        <table style={{ borderCollapse: 'collapse', width: '100%', fontSize: 13 }}>
          <thead>
            <tr>
              <th style={th({ first: true })}/>
              {yrs.map((y) => (
                <th key={y} style={th()}>{y.toUpperCase()}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {rows.map(([label, key, neg, role], ri) => (
              <tr key={ri} style={{
                background: role === 'total' ? 'var(--mal-primary-50)' : 'transparent',
                fontWeight: role === 'total' ? 600 : 400,
              }}>
                <td style={td({ label: true, sub: role === 'sub' })}>{label}</td>
                {yrs.map((y) => {
                  const v = data.pnl[y][key];
                  const display = neg ? -v : v;
                  return (
                    <td key={y} style={td({ negative: display < 0 })}>{display.toFixed(1)}</td>
                  );
                })}
              </tr>
            ))}
            {/* Ratios row */}
            <tr style={{ background: 'var(--mal-surface-2)' }}>
              <td style={td({ label: true, role: 'header' })}>{isAr ? 'العائد على الأصول' : 'ROA (%)'}</td>
              {yrs.map((y) => <td key={y} style={td()}>{pct(data.ratios[y].roaPct, 2)}</td>)}
            </tr>
            <tr style={{ background: 'var(--mal-surface-2)' }}>
              <td style={td({ label: true })}>RAROC (%)</td>
              {yrs.map((y) => <td key={y} style={td()}>{pct(data.ratios[y].rarocPct, 1)}</td>)}
            </tr>
          </tbody>
        </table>
      </div>
    </ChartCard>
  );
}

// ============================================================
// Risk section — PD/LGD/EAD per track + stress
// ============================================================
function RiskSection({ data, isMobile, isAr }) {
  const r = data.risk;
  return (
    <div data-tour-id="econ-risk-card">
    <ChartCard title={isAr ? 'طبقة المخاطر · PD/LGD/EAD لكل مسار' : 'Risk layer · PD/LGD/EAD per track'}
               sub={isAr ? 'إطار Basel III IRB Foundation · EL = PD × LGD × EAD' : 'Basel III IRB Foundation · EL = PD × LGD × EAD'}>
      <div style={{ overflowX: 'auto' }}>
        <table style={{ borderCollapse: 'collapse', width: '100%', fontSize: 13 }}>
          <thead>
            <tr>
              <th style={th({ first: true })}>{isAr ? 'المعيار' : 'Parameter'}</th>
              <th style={th()}>Pay-30</th>
              <th style={th()}>BNPL</th>
              <th style={th()}>{isAr ? 'تمديد' : 'Extension'}</th>
              <th style={th()}>{isAr ? 'مرجح' : 'Weighted'}</th>
              <th style={th()}>{isAr ? 'إجهاد ١.٥×' : 'Stress 1.5×'}</th>
            </tr>
          </thead>
          <tbody>
            <RiskRow label={isAr ? 'PD (٪/سنة)' : 'PD (% p.a.)'}
                     v1={r.pay30.pd} v2={r.bnpl.pd} v3={r.ext.pd}
                     w={(r.pay30.pd * 0.4 + r.bnpl.pd * 0.5 + r.ext.pd * 0.1)}
                     stress={r.pay30.stressed * 100 / r.pay30.pd ? 1.5 : 1.5}
                     stressLabel="× 1.5"/>
            <RiskRow label={isAr ? 'LGD (٪)' : 'LGD (%)'}
                     v1={r.pay30.lgd} v2={r.bnpl.lgd} v3={r.ext.lgd}
                     w={(r.pay30.lgd * 0.4 + r.bnpl.lgd * 0.5 + r.ext.lgd * 0.1)}
                     stressLabel="—"/>
            <RiskRow label="EAD (%)"
                     v1={r.pay30.ead} v2={r.bnpl.ead} v3={r.ext.ead}
                     w={(r.pay30.ead * 0.4 + r.bnpl.ead * 0.5 + r.ext.ead * 0.1)}
                     stressLabel="—"/>
            <tr style={{ background: 'var(--mal-primary-50)', fontWeight: 600 }}>
              <td style={td({ label: true })}>{isAr ? 'معدل الخسارة الصافي' : 'Net loss rate (% of book)'}</td>
              <td style={td()}>{pct(r.pay30.netLoss, 2)}</td>
              <td style={td()}>{pct(r.bnpl.netLoss, 2)}</td>
              <td style={td()}>{pct(r.ext.netLoss, 2)}</td>
              <td style={td()}>{pct(r.pay30.netLoss * 0.4 + r.bnpl.netLoss * 0.5 + r.ext.netLoss * 0.1, 2)}</td>
              <td style={td({ tone: 'danger' })}>{pct(r.pay30.stressed * 0.4 + r.bnpl.stressed * 0.5 + r.ext.stressed * 0.1, 2)}</td>
            </tr>
          </tbody>
        </table>
      </div>
      <div style={{ marginTop: 14, padding: 12, background: 'var(--mal-surface-2)',
                    borderRadius: 10, fontSize: 11.5, color: 'var(--mal-mid)', lineHeight: 1.65 }}>
        {isAr
          ? 'الخسارة المرجحة المتوقعة ٢.٦٪ من الكتاب · إجهاد CBUAE ٢٠٢٠ (PD ×١.٥) يرفعها إلى ٤.٠٪ — لا تزال مغطاة بالهامش.'
          : 'Weighted expected loss 2.6% of book · CBUAE-2020 stress (PD ×1.5) lifts to ~4.0% — still margin-covered.'}
      </div>
    </ChartCard>
    </div>
  );
}

function RiskRow({ label, v1, v2, v3, w, stressLabel }) {
  return (
    <tr>
      <td style={td({ label: true })}>{label}</td>
      <td style={td()}>{v1.toFixed(1)}</td>
      <td style={td()}>{v2.toFixed(1)}</td>
      <td style={td()}>{v3.toFixed(1)}</td>
      <td style={td()}>{w.toFixed(1)}</td>
      <td style={td({ tone: 'muted' })}>{stressLabel}</td>
    </tr>
  );
}

