function VintageCohortsSection({ data, isMobile, isAr }) {
  const v = data.vintage;
  return (
    <div data-tour-id="econ-vintage" style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : '1fr 1fr', gap: 22 }}>
      <ChartCard title={isAr ? 'الخسارة التراكمية · شهر بعد شهر' : 'Cumulative loss curve · M0 → M24'}
                 sub={isAr ? 'لوغاريتمي · ٣٠٪ في M0–6 · ٥٠٪ M7–18 · ٢٠٪ M19–24'
                            : 'Lognormal: 30% M0–6 · 50% M7–18 · 20% M19–24'}>
        <VintageLossSvg vintage={v}/>
      </ChartCard>
      <ChartCard title={isAr ? 'الخسارة العمرية لكل دفعة' : 'Lifetime loss per vintage'}
                 sub={isAr ? `إجمالي ٣ سنوات: ${aedM(v.totalLifetimeLoss, 1)} على ${aedM(v.totalAdvanced, 0)} مستحق`
                            : `Y1+Y2+Y3 total: ${aedM(v.totalLifetimeLoss, 1)} on ${aedM(v.totalAdvanced, 0)} advanced`}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginTop: 6 }}>
          {['y1','y2','y3'].map((y) => {
            const vt = v.perVintage[y];
            const max = Math.max(...['y1','y2','y3'].map((k) => v.perVintage[k].lossM));
            const w = (vt.lossM / max) * 100;
            return (
              <div key={y}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12, marginBottom: 4 }}>
                  <span style={{ color: 'var(--mal-mid)' }}>{y.toUpperCase()} {isAr ? 'دفعة' : 'vintage'}</span>
                  <span style={{ fontFamily: 'var(--mal-font-mono)' }}>
                    {aedM(vt.lossM, 1)} <span style={{ color: 'var(--mal-mid)' }}>· {pct(vt.lossPct * 100, 2)}</span>
                  </span>
                </div>
                <div style={{ height: 10, borderRadius: 999, background: 'var(--mal-surface-2)', overflow: 'hidden' }}>
                  <div style={{ width: w + '%', height: '100%', background: 'var(--mal-primary)' }}/>
                </div>
                <div style={{ fontSize: 10.5, color: 'var(--mal-mid-2)', marginTop: 2 }}>
                  {isAr ? 'مستحق' : 'advanced'}: {aedM(vt.advanced, 0)}
                </div>
              </div>
            );
          })}
        </div>
        <div style={{ marginTop: 14, padding: 12, background: 'var(--mal-surface-2)', borderRadius: 10, fontSize: 11.5, color: 'var(--mal-mid)', lineHeight: 1.6 }}>
          {isAr
            ? 'الخسارة العمرية ٠.٦٠٪ من المستحق — منخفضة جداً · يعكس ضمان الفاتورة'
            : 'Lifetime loss ratio 0.60% of advanced — very low · reflects invoice collateral'}
        </div>
      </ChartCard>
    </div>
  );
}

