function BeBlock({ title, main, sub, status, tone }) {
  return (
    <div style={{
      padding: 14, borderRadius: 12,
      border: '1px solid var(--mal-line)', background: 'var(--mal-surface-2)',
    }}>
      <div style={{ fontSize: 10.5, fontWeight: 600, letterSpacing: '.06em',
                    textTransform: 'uppercase', color: 'var(--mal-mid-2)', marginBottom: 4 }}>{title}</div>
      <div style={{ fontFamily: 'var(--mal-font-display)', fontStyle: 'italic',
                    fontSize: 26, lineHeight: 1, color: 'var(--mal-ink)' }}>{main}</div>
      <div style={{ fontSize: 11, color: 'var(--mal-mid)', marginTop: 6, lineHeight: 1.5 }}>{sub}</div>
      {status && (
        <div style={{ fontSize: 11, fontWeight: 600, marginTop: 8,
                      color: tone === 'success' ? 'var(--mal-success)' : 'var(--mal-danger)' }}>
          ✓ {status}
        </div>
      )}
    </div>
  );
}

// ============================================================
// Sensitivity heatmap (PD × COF)
// ============================================================
function SensitivitySection({ data, isAr }) {
  const s = data.sensitivity;
  if (!s.grid.length) return null;
  const flat = s.grid.flat();
  const min = Math.min(...flat), max = Math.max(...flat);
  const cellColor = (v) => {
    const t = max === min ? 0.5 : (v - min) / (max - min);
    return v < 0 ? `rgba(214,80,78,${0.15 + 0.55 * (1 - t)})` : `rgba(126,199,159,${0.15 + 0.65 * t})`;
  };
  const baseI = s.cofLevels.indexOf(6.5);
  const baseJ = s.pdMultipliers.indexOf(1.0);
  return (
    <div data-tour-id="econ-sensitivity">
    <ChartCard title={isAr ? 'حساسية المساهمة الصافية · Y3' : 'Sensitivity · Y3 net contribution (AED M)'}
               sub={isAr ? 'الصفوف: تكلفة التمويل · الأعمدة: مضاعف PD' : 'Rows: COF · Cols: PD multiplier'}>
      <div style={{ overflowX: 'auto' }}>
        <table style={{ borderCollapse: 'separate', borderSpacing: 4, fontFamily: 'var(--mal-font-mono)', fontSize: 12 }}>
          <thead>
            <tr>
              <th style={{ padding: 6, color: 'var(--mal-mid)', fontSize: 11 }}/>
              {s.pdMultipliers.map((p, i) => (
                <th key={i} style={{ padding: 6, color: 'var(--mal-mid)', fontSize: 11, textAlign: 'center' }}>
                  {p.toFixed(1)}× PD
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {s.grid.map((row, ri) => (
              <tr key={ri}>
                <td style={{ padding: 6, color: 'var(--mal-mid)', fontSize: 11, fontWeight: 500, textAlign: 'end' }}>
                  COF {s.cofLevels[ri].toFixed(1)}%
                </td>
                {row.map((v, ci) => (
                  <td key={ci} style={{
                    width: 78, textAlign: 'center', padding: '8px 6px',
                    background: cellColor(v),
                    border: ri === baseI && ci === baseJ ? '2px solid var(--mal-primary)' : '1px solid var(--mal-line-2)',
                    borderRadius: 6, color: 'var(--mal-ink)',
                  }}>{v.toFixed(0)}M</td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </ChartCard>
    </div>
  );
}

