// ============================================================
// VintageLossSvg — bespoke 3-line chart, all keys explicit
// ============================================================
function VintageLossSvg({ vintage }) {
  const months = vintage.lossCurve.months;
  const series = [
    { id: 'y3', label: 'Y3 cohort', values: vintage.lossCurveAED.y3, color: 'var(--mal-primary)' },
    { id: 'y2', label: 'Y2 cohort', values: vintage.lossCurveAED.y2, color: 'var(--mal-primary-3)' },
    { id: 'y1', label: 'Y1 cohort', values: vintage.lossCurveAED.y1, color: 'var(--mal-iri-2)' },
  ];
  const allVals = series.flatMap((s) => s.values);
  const maxV = Math.max(...allVals, 1);
  const W = 480, H = 220, padTop = 16, padBottom = 28, padX = 30;
  const innerW = W - padX * 2, innerH = H - padTop - padBottom;
  const xAt = (i) => padX + (i / (months.length - 1 || 1)) * innerW;
  const yAt = (v) => padTop + (1 - v / maxV) * innerH;
  return (
    <div>
      <svg viewBox={`0 0 ${W} ${H}`} style={{ width: '100%', height: H, display: 'block' }} role="img" aria-label="vintage loss curves">
        {[0, 0.5, 1].map((p) => (
          <line key={'grid-' + p}
                x1={padX} y1={padTop + p * innerH}
                x2={W - padX} y2={padTop + p * innerH}
                stroke="var(--mal-line)" strokeDasharray="2 4" strokeWidth="1"/>
        ))}
        {months.map((m, i) => i % 4 === 0 ? (
          <text key={'tick-' + i} x={xAt(i)} y={H - padBottom + 16} textAnchor="middle"
                fontSize="10" fill="var(--mal-mid)">{m}</text>
        ) : null)}
        {series.map((s) => {
          const points = s.values.map((v, i) => `${xAt(i)},${yAt(v)}`).join(' ');
          return (
            <polyline key={'line-' + s.id} points={points} fill="none"
                      stroke={s.color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
          );
        })}
      </svg>
      <div style={{ display: 'flex', gap: 14, justifyContent: 'center', marginTop: 8, fontSize: 11 }}>
        {series.map((s) => (
          <span key={'leg-' + s.id} style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <span style={{ width: 10, height: 3, background: s.color, borderRadius: 2, display: 'inline-block' }}/>
            <span style={{ color: 'var(--mal-mid)' }}>
              {s.label} · {(s.values[s.values.length - 1] || 0).toFixed(1)}M
            </span>
          </span>
        ))}
      </div>
    </div>
  );
}

// ============================================================
// Generic ChartCard
// ============================================================
function ChartCard({ title, sub, children }) {
  return (
    <div className="mal-fade-up" style={{
      background: 'var(--mal-paper)', border: '1px solid var(--mal-line)',
      borderRadius: 'var(--mal-r-lg)', padding: 18,
    }}>
      <div style={{ marginBottom: 12 }}>
        <div style={{ fontSize: 13, fontWeight: 600, color: 'var(--mal-ink)' }}>{title}</div>
        {sub && <div style={{ fontSize: 11, color: 'var(--mal-mid)', marginTop: 2 }}>{sub}</div>}
      </div>
      {children}
    </div>
  );
}

// ============================================================
// Cell-style helpers
// ============================================================
function th({ first = false } = {}) {
  return {
    textAlign: first ? 'start' : 'end',
    padding: '8px 10px', fontSize: 11,
    textTransform: 'uppercase', letterSpacing: '.06em',
    color: 'var(--mal-mid)',
    borderBottom: '2px solid var(--mal-line)',
  };
}
function td({ label = false, sub = false, negative = false, tone, role } = {}) {
  const colors = {
    success: 'var(--mal-success)', danger: 'var(--mal-danger)', muted: 'var(--mal-mid-2)',
  };
  return {
    padding: '8px 10px', textAlign: label ? 'start' : 'end',
    borderBottom: '1px solid var(--mal-line-2)',
    color: tone ? colors[tone] : (negative ? 'var(--mal-danger)' : (label ? 'var(--mal-mid)' : 'var(--mal-ink)')),
    fontFamily: label ? 'inherit' : 'var(--mal-font-mono)',
    paddingInlineStart: sub ? 22 : (label ? 10 : undefined),
    fontWeight: role === 'header' ? 600 : undefined,
  };
}

